require "property.BaseProperty"

FallTNTProperty = class("FallTNTProperty", BaseProperty)

function FallTNTProperty:onPlayerBeAttack(player, source, damage)
    local pos = player:getPosition()
    local v3i = VectorUtil.newVector3i(pos.x, pos.y, pos.z)
